export function CompanyLogo({ name, size = 40, className = "" }: CompanyLogoProps) {
  let key = name.toLowerCase().trim().replace(/\s+/g, "");
  if (key === "salesfore") {
    key = "salesforce";
  }
  const logo = LOGOS[key];

  if (!logo) {
    // Fallback: vivid gradient with large initial letter
    const colors: [string, string][] = [
      ["#0060b9", "#3b82f6"],
      ["#0891b2", "#67e8f9"],
      ["#19a672", "#6ee7b7"],
      ["#d97706", "#fcd34d"],
      ["#dc2626", "#f87171"],
      ["#7c3aed", "#c4b5fd"],
    ];
    const [from, to] = colors[name.charCodeAt(0) % colors.length];

    return (
      <div
        className={`flex items-center justify-center rounded-xl font-black text-white shadow-sm ${className}`}
        style={{
          width: size,
          height: size,
          fontSize: size * 0.42,
          background: `linear-gradient(135deg, ${from} 0%, ${to} 100%)`,
          flexShrink: 0,
        }}
      >
        {name.charAt(0).toUpperCase()}
      </div>
    );
  }

  const pad = logo.pad ?? 0.13;

  return (
    <div
      className={`flex items-center justify-center rounded-xl shadow-sm overflow-hidden ${className}`}
      style={{
        width: size,
        height: size,
        background: logo.bg,
        padding: size * pad,
        border: logo.bg === "#fff" ? "1px solid #e1e5ea" : "none",
        flexShrink: 0,
      }}
    >
      <div
        style={{
          width: "100%",
          height: "100%",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        {logo.svg}
      </div>
    </div>
  );
}

export default CompanyLogo;
